import './CollapsableFutureVerticalTimeline.scss';

import type { FC } from 'react';
import React from 'react';

import type { AtomPosition, CollapsableTimelineProps, TimelineIconType } from '../../Timeline.types';
import { calcStepPosition } from '../../utils';
import { VerticalContent } from '../VerticalContent';

export const CollapsableFutureVerticalTimeline: FC<CollapsableTimelineProps> = ({ steps }) => {
	const stepsLength = steps.length;

	if (!stepsLength) {
		return null;
	}

	return (
		<>
			{steps.map((step, index) => {
				const position: AtomPosition = calcStepPosition(index, stepsLength - 1);
				const type: TimelineIconType = 'inactive';

				return (
					<div key={step.id} className="dsb_timeline-future-step">
						<VerticalContent {...step} type={type} position={position} />
					</div>
				);
			})}
		</>
	);
};
